const body = $input.first().json.body;
const session = body.data.object;

const customerId = session.customer;
const subscriptionId = session.subscription;
const sessionId = session.id;
const customerEmail = session.customer_details?.email || '';
const customerName = session.customer_details?.name || 'Valued Client';
const paymentStatus = session.payment_status;

const plans = {
  'price_1TDckaECS71NQsk8DdNsWy1o': { name: 'Standard', billing: 'Monthly', amount: '$497/mo', setupFeePrice: 'price_1TEKKrECS71NQsk8Mw3Z8CoC', minutes: '475', jotformUrl: 'https://form.jotform.com/260795139953066' },
  'price_1TDckiECS71NQsk8fqDio8pw': { name: 'Standard', billing: 'Annual',  amount: '$414/mo', setupFeePrice: 'price_1TEKKrECS71NQsk8Mw3Z8CoC', minutes: '475', jotformUrl: 'https://form.jotform.com/260795139953066' },
  'price_1TDclGECS71NQsk8OoLoMV0q': { name: 'Premium',  billing: 'Monthly', amount: '$997/mo', setupFeePrice: 'price_1TEKKvECS71NQsk8vWGjHLUP', minutes: '1,000', jotformUrl: 'https://form.jotform.com/260819259556671' },
  'price_1TDclPECS71NQsk8S9bAPGoJ': { name: 'Premium',  billing: 'Annual',  amount: '$831/mo', setupFeePrice: 'price_1TEKKvECS71NQsk8vWGjHLUP', minutes: '1,000', jotformUrl: 'https://form.jotform.com/260819259556671' }
};

const priceId = session.metadata?.price_id || '';
let plan = plans[priceId];

if (!plan && session.line_items?.data) {
  const lineItem = session.line_items.data.find(li => plans[li.price?.id]);
  if (lineItem) plan = plans[lineItem.price.id];
}

if (!plan) plan = { name: 'Standard', billing: 'Monthly', amount: '$497/mo', setupFeePrice: 'price_1TEKKrECS71NQsk8Mw3Z8CoC', minutes: '475', jotformUrl: 'https://form.jotform.com/260795139953066' };

const signupDate = new Date(session.created * 1000).toLocaleDateString('en-AU', { day: '2-digit', month: 'long', year: 'numeric' });

const emailHtml = `<!DOCTYPE html><html><head><meta charset='utf-8'></head><body style="font-family:Helvetica,Arial,sans-serif;background:#f5f5f5;margin:0;padding:0;"><div style="max-width:580px;margin:30px auto;background:#fff;border-radius:12px;overflow:hidden;"><div style="background:#6B63E8;padding:32px 36px;text-align:center;"><h1 style="color:#fff;font-size:22px;margin:0;font-weight:bold;">Payment Confirmed — One Last Step!</h1><p style="color:#D0CCFF;font-size:13px;margin:6px 0 0;">Syntharra AI Solutions</p></div><div style="padding:32px 36px;"><p style="font-size:16px;color:#1C1C2E;font-weight:bold;margin-bottom:12px;">Hi ${customerName},</p><p style="font-size:14px;color:#5F5E5A;line-height:1.7;margin-bottom:16px;">Your payment has been received and your Syntharra AI Receptionist subscription is confirmed. To activate your service, please complete your onboarding form — this is how we build and configure your AI Receptionist to your exact business requirements.</p><div style="background:#EEEDFE;border-radius:10px;padding:18px 22px;margin:20px 0;"><p style="margin:4px 0;font-size:13px;color:#3C3489;"><strong style="color:#1C1C2E;">Plan:</strong> ${plan.name} — AI Receptionist${plan.name === 'Premium' ? ' Pro' : ''}</p><p style="margin:4px 0;font-size:13px;color:#3C3489;"><strong style="color:#1C1C2E;">Billing:</strong> ${plan.billing} (${plan.amount})</p><p style="margin:4px 0;font-size:13px;color:#3C3489;"><strong style="color:#1C1C2E;">Minutes Included:</strong> ${plan.minutes} minutes/month</p><p style="margin:4px 0;font-size:13px;color:#3C3489;"><strong style="color:#1C1C2E;">Payment Date:</strong> ${signupDate}</p></div><p style="font-size:14px;color:#5F5E5A;line-height:1.7;margin-bottom:16px;">The form takes less than 5 minutes and covers your business details, preferred agent name and voice, call handling preferences, and any custom instructions for your AI Receptionist.</p><div style="text-align:center;margin:28px 0;"><a href="${plan.jotformUrl}" style="display:inline-block;background:#6B63E8;color:#ffffff;font-size:15px;font-weight:bold;padding:14px 36px;border-radius:8px;text-decoration:none;">Complete My Onboarding Form &rarr;</a></div><p style="font-size:12px;color:#888;text-align:center;margin-top:8px;">Your AI Receptionist will be live within 1 business day of form submission.</p><p style="font-size:14px;color:#5F5E5A;line-height:1.7;">Any questions? Simply reply to this email and we will get back to you promptly.</p><p style="font-size:14px;color:#5F5E5A;line-height:1.7;">Welcome aboard,<br><strong>The Syntharra Team</strong></p></div><div style="background:#f5f5f5;padding:18px 36px;text-align:center;font-size:11px;color:#888780;">syntharra.com &nbsp;&bull;&nbsp; AI Receptionist Solutions for the Trade Industry &nbsp;&bull;&nbsp; Available Worldwide</div></div></body></html>`;

return [{ json: { customerId, subscriptionId, sessionId, customerEmail, customerName, planName: plan.name, planBilling: plan.billing, planAmount: plan.amount, setupFeePrice: plan.setupFeePrice, minutes: plan.minutes, jotformUrl: plan.jotformUrl, emailHtml, paymentStatus, signupDate } }];

// Send Welcome Email via SMTP2GO
const data = $('Extract Session Data').first().json;
const customerEmail = data.customerEmail || '';
const emailHtml = data.emailHtml || '';
const subject = 'Welcome to Syntharra — One Last Step to Activate Your AI Receptionist';

if (!customerEmail || !emailHtml) {
  console.log('[WELCOME] Missing email or HTML');
  return { sent: false };
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.smtp2go.com/v3/email/send',
    headers: { 'Content-Type': 'application/json' },
    body: {
      api_key: 'api-0BE30DA64A074BC79F28BE6AEDC9DB9E',
      sender: 'Syntharra AI <noreply@syntharra.com>',
      to: [customerEmail],
      subject: subject,
      html_body: emailHtml
    },
    json: true
  });
  console.log('[WELCOME] Sent to ' + customerEmail);
  return { sent: true, email: customerEmail };
} catch (e) {
  console.log('[WELCOME] Failed:', e.message);
  return { sent: false, error: e.message };
}

